(function(){
'use strict';
const KEY='arcane-pets-v1',PET_CORE=150,CFG={seek:720,collect:34,gemSweep:120,follow:4.2,run:260};
const PETS=[
  {id:'sprigatito',name:'新叶喵',src:'./assets/pokemom/sprigatito.gif'},
  {id:'fuecoco',name:'呆火鳄',src:'./assets/pokemom/fuecoco.gif'},
  {id:'quaxly',name:'润水鸭',src:'./assets/pokemom/quaxly.gif'}
];
let raf=0,state={owned:false,selected:'sprigatito'},ready=false,petImg=null,lastEquipSave=0;
const $=id=>document.getElementById(id),esc=v=>String(v??'').replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m]));
function notice(t){try{typeof showNotice==='function'&&showNotice(t)}catch(_){}}
function petDef(id=state.selected){return PETS.find(p=>p.id===id)||PETS[0]}
async function init(){if(ready)return state;try{let v=await StorageSync.get(KEY);state={owned:!!v?.owned,selected:petDef(v?.selected).id};ready=true}catch(e){ready=true;console.error('宠物数据读取失败:',e.message,e.stack)}return state}
async function save(){try{await StorageSync.put(KEY,state,'宠物')}catch(e){console.error('宠物数据保存失败:',e.message,e.stack)}}
function hasPet(){return !!state.owned}
function active(){return !!(hasPet()&&window.S&&S.run&&S.player&&!S.rift?.active&&S.mapId!=='rift')}
function num(name,fallback){try{return typeof window[name]==='number'?window[name]:eval(`typeof ${name}==='number'?${name}:${fallback}`)}catch(_){return fallback}}
function ensureUi(){
  if(!$('petPanel'))document.querySelector('.game')?.insertAdjacentHTML('beforeend',`<section id="petPanel" class="overlay hidden"><div class="panel petPanelBox"><h1 class="title">宠物</h1><div id="petPanelBody" class="shopDetailBody"></div><p class="sub"><button id="petPanelClose" class="ghostBtn" type="button">关闭</button></p></div></section>`);
  if(!$('petLayer'))document.querySelector('.game')?.insertAdjacentHTML('beforeend',`<div id="petLayer" style="position:absolute;inset:0;pointer-events:none;z-index:13;overflow:hidden"><img id="petFollower" alt="宠物" style="position:absolute;width:26px;height:26px;object-fit:contain;transform:translate(-50%,-70%);display:none;filter:drop-shadow(0 2px 4px #000) drop-shadow(0 0 6px rgba(125,211,252,.5));image-rendering:auto"></div>`);
  petImg=$('petFollower');$('petPanelClose')?.addEventListener('click',()=>{$('petPanel')?.classList.add('hidden');if(S&&!S.run)S.paused=false},{once:true});
  if(!$('petStyle'))document.head.insertAdjacentHTML('beforeend',`<style id="petStyle">.petEquipBtn{margin-left:6px!important;min-width:34px!important;padding:5px 9px!important;border-radius:10px!important;background:rgba(56,189,248,.18)!important;color:#dff8ff!important;border:1px solid rgba(125,211,252,.6)!important;box-shadow:0 0 12px rgba(56,189,248,.22)!important}.petStatusCard{display:grid;gap:10px;text-align:left}.petPickGrid{display:grid;grid-template-columns:repeat(3,1fr);gap:10px}.petPick{min-height:116px!important;padding:8px!important;border-radius:14px!important}.petPick.selected{outline:2px solid #facc15!important;box-shadow:0 0 18px rgba(250,204,21,.42)!important}.petPick img,.petOrbPreview img{image-rendering:auto;object-fit:contain}.petPick img{width:64px;height:64px}.petOrbPreview{width:88px;height:88px;margin:0 auto 8px;display:grid;place-items:center;border-radius:50%;background:radial-gradient(circle,rgba(125,211,252,.22),rgba(14,165,233,.08) 65%,transparent);box-shadow:0 0 22px rgba(56,189,248,.38)}.petOrbPreview img{max-width:82px;max-height:82px}</style>`)
}
function petCards(){return PETS.map(p=>`<button class="petPick ${state.selected===p.id?'selected':''}" data-pet-pick="${esc(p.id)}" ${hasPet()?'':'disabled'}><img src="${esc(p.src)}" alt="${esc(p.name)}"><b>${esc(p.name)}</b><small>${hasPet()?(state.selected===p.id?'出战中':'点击出战'):'购买后可选'}</small></button>`).join('')}
function panelHtml(){let p=petDef();return `<div class="petStatusCard"><div class="petOrbPreview"><img src="${esc(p.src)}" alt="${esc(p.name)}"></div><p><b>${esc(p.name)}</b> · 拾取宠物</p><p>普通和无尽模式会主动跑向经验球和装备拾取；没有掉落物时回到角色身边。大秘境不生效。</p><p><b>状态：</b>${hasPet()?'已拥有，进入普通/无尽自动出战':'未拥有'}</p><div class="petPickGrid">${petCards()}</div>${hasPet()?'':'<p><b>价格：</b>'+PET_CORE+' 魔核，购买后可从三只宠物中选择出战。</p>'}</div>`}
function openPanel(){ensureUi();$('petPanelBody').innerHTML=panelHtml();$('petPanel')?.classList.remove('hidden')}
async function buyPet(){let b=$('shopDetailBuy');if(hasPet()){openPanel();return}try{b&&(b.disabled=true,b.textContent='购买中...');await init();await Progression?.init?.();if(hasPet()){b&&(b.disabled=false,b.textContent='查看宠物');openPanel();return}if(!await Progression.spendCore(PET_CORE)){b&&(b.disabled=false,b.textContent='购买宠物');$('shopDetailMsg')&&($('shopDetailMsg').textContent='魔核不足');notice('魔核不足');return}state.owned=true;state.selected=state.selected||PETS[0].id;await save();$('shopDetailBody')&&($('shopDetailBody').innerHTML=panelHtml());$('shopDetailMsg')&&($('shopDetailMsg').textContent='购买成功：宠物已解锁');b&&(b.disabled=false,b.textContent='查看宠物');notice('宠物已解锁');try{renderProgression?.()}catch(_){}}catch(e){b&&(b.disabled=false,b.textContent='购买宠物');$('shopDetailMsg')&&($('shopDetailMsg').textContent='购买失败，请重试');console.error('宠物购买失败:',e.code,e.message,e.stack)}}
function shopDetail(){return{title:'宠物',body:panelHtml(),buyText:hasPet()?'查看宠物':'购买宠物',buy:hasPet()?openPanel:buyPet}}
function ensurePet(){if(!active())return null;let p=S.player,pet=S.petCollector;if(!pet||pet.mapId!==S.mapId){pet={x:p.x-52,y:p.y+36,mapId:S.mapId,target:null};S.petCollector=pet}return pet}
function dist2(a,b){let x=a.x-b.x,y=a.y-b.y;return x*x+y*y}
function findTarget(pet){let best=null,bd=CFG.seek*CFG.seek;for(const d of S.equipGround||[])if(d&&!d.dead&&d.item){let v=dist2(pet,d);if(v<bd){bd=v;best={type:'equip',obj:d}}}for(const g of S.gems||[])if(g&&!g.dead){let v=dist2(pet,g);if(v<bd){bd=v;best={type:'gem',obj:g}}}return best}
function moveToward(pet,tx,ty,dt,speed=CFG.run){let dx=tx-pet.x,dy=ty-pet.y,d=Math.hypot(dx,dy)||1,step=Math.min(d,speed*dt);pet.x+=dx/d*step;pet.y+=dy/d*step;return d}
function movePet(dt,pet){let t=findTarget(pet),p=S.player;if(t){pet.target=t;moveToward(pet,t.obj.x,t.obj.y,dt);return}let tx=p.x-54+Math.cos((S.time||0)*1.7)*18,ty=p.y+36+Math.sin((S.time||0)*2.1)*12;pet.target=null;pet.x+=(tx-pet.x)*Math.min(1,dt*CFG.follow);pet.y+=(ty-pet.y)*Math.min(1,dt*CFG.follow)}
function addPickupFx(x,y,c,size){S.parts=S.parts||[];S.parts.push({x,y,vx:0,vy:-8,life:.32,max:.32,a:1,c,boom:size||34})}
function rarityColor(item){try{return typeof eqRarityColor==='function'?eqRarityColor(item?.rarity):'#facc15'}catch(_){return'#facc15'}}
function sweepGems(pet){let gained=0,rad=CFG.gemSweep*CFG.gemSweep;for(const g of S.gems||[])if(g&&!g.dead&&dist2(pet,g)<=rad){g.dead=true;gained+=Number(g.v)||0;addPickupFx(g.x,g.y,'#38bdf8',20)}if(gained>0){S.player.xp+=gained;S.gems=(S.gems||[]).filter(g=>!g.dead)}}
function collectTarget(pet){let t=pet.target,o=t?.obj;if(!o||o.dead||dist2(pet,o)>CFG.collect*CFG.collect)return;if(t.type==='gem'){sweepGems(pet);return}if(!o.item)return;o.dead=true;S.equipDrops=S.equipDrops||[];S.equipDrops.unshift(o.item);S.dropsSinceAltar=(S.dropsSinceAltar||0)+1;S.equipGround=(S.equipGround||[]).filter(d=>!d.dead);addPickupFx(o.x,o.y,rarityColor(o.item),64);notice(`宠物拾取装备：${o.item.name}`);if((S.time||0)-lastEquipSave>.8){lastEquipSave=S.time||0;try{if(typeof saveGame==='function')Promise.resolve(saveGame()).catch(e=>console.error('宠物拾取保存失败:',e.message,e.stack))}catch(e){console.error('宠物拾取保存失败:',e.message,e.stack)}}try{if(S.dropsSinceAltar>=5&&!S.rift?.guardianKilled&&typeof openAltar==='function')openAltar()}catch(e){console.error('宠物打开净化祭坛失败:',e.message,e.stack)}}
function updatePet(dt){let pet=ensurePet();if(!pet)return;movePet(dt,pet);collectTarget(pet)}
function patchUpdate(){if(typeof window.updateObjs!=='function'||window.updateObjs._petLooter)return false;let base=window.updateObjs;window.updateObjs=function(dt){let r=base.apply(this,arguments);try{updatePet(dt||0)}catch(e){console.error('宠物拾取更新失败:',e.message,e.stack)}return r};window.updateObjs._petLooter=true;return true}
function patchEquipment(){if(typeof window.renderEquipment!=='function'||window.renderEquipment._petLooter)return false;let base=window.renderEquipment;window.renderEquipment=function(){let r=base.apply(this,arguments);addEquipButton();return r};window.renderEquipment._petLooter=true;addEquipButton();return true}
function addEquipButton(){let sub=$('equipSub');if(!sub||sub.querySelector('[data-pet-open]'))return;let ref=sub.querySelector('[data-eq-class-switch]')||sub.firstChild,btn=document.createElement('button');btn.className='petEquipBtn';btn.type='button';btn.dataset.petOpen='1';btn.textContent='宠';btn.title='宠物';ref?.after?ref.after(btn):sub.prepend(btn)}
function drawPet(){ensureUi();if(!petImg)return;let pet=active()?S.petCollector:null;if(!pet){petImg.style.display='none';return}let p=petDef();if(!petImg.src.includes(p.src.replace('./','')))petImg.src=p.src;let camX=num('CAMX',0),camY=num('CAMY',0),vw=num('W',innerWidth),vh=num('H',innerHeight),host=$('c'),cw=host?.clientWidth||innerWidth,ch=host?.clientHeight||innerHeight,moving=!!pet.target,bob=moving?Math.abs(Math.sin((S.time||0)*15))*5:Math.sin((S.time||0)*4)*1.5,squash=moving?(.92+Math.abs(Math.sin((S.time||0)*15))*.12):1,x=(pet.x-camX)/vw*cw,y=(pet.y-camY)/vh*ch-bob;petImg.style.display='block';petImg.style.left=x+'px';petImg.style.top=y+'px';petImg.style.transform=`translate(-50%,-70%) scaleX(${pet.target&&pet.target.obj.x<pet.x?-1:1}) scaleY(${squash})`}
async function pickPet(id){await init();if(!hasPet())return;state.selected=petDef(id).id;await save();openPanel();notice('宠物出战：'+petDef().name)}
function bind(){document.addEventListener('click',e=>{let b=e.target.closest('[data-pet-open]');if(b){e.preventDefault();e.stopPropagation();openPanel();return}let p=e.target.closest('[data-pet-pick]');if(p){e.preventDefault();e.stopPropagation();pickPet(p.dataset.petPick)}},true)}
function loop(){drawPet();raf=requestAnimationFrame(loop)}
function boot(){ensureUi();init();bind();if(!patchUpdate())setTimeout(boot,200);if(!patchEquipment())setTimeout(patchEquipment,300);if(!raf)loop()}
window.PetLooter={init,hasPet,shopDetail,openPanel,buyPet};
if(document.readyState==='loading')document.addEventListener('DOMContentLoaded',boot);else boot();
})();
